import{c as o,Q as e,j as r,m as a}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Claude Code Tips From the Guy Who Built It","description":"","frontmatter":{"url":"https://www.anup.io/35-claude-code-tips-from-the-guy-who-built-it/","title":"Claude Code Tips From the Guy Who Built It","type":"article"},"headers":[],"relativePath":"research/ai-articles/13-anup-35-boris-tips.md","filePath":"research/ai-articles/13-anup-35-boris-tips.md","lastUpdated":1779894392000}'),s={name:"research/ai-articles/13-anup-35-boris-tips.md"};function i(l,t,n,u,d,h){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="claude-code-tips-from-the-guy-who-built-it" tabindex="-1">Claude Code Tips From the Guy Who Built It <a class="header-anchor" href="#claude-code-tips-from-the-guy-who-built-it" aria-label="Permalink to &quot;Claude Code Tips From the Guy Who Built It&quot;">​</a></h1><p><strong>原始 URL</strong>: <a href="https://www.anup.io/35-claude-code-tips-from-the-guy-who-built-it/" target="_blank" rel="noreferrer">https://www.anup.io/35-claude-code-tips-from-the-guy-who-built-it/</a></p><p><strong>作者</strong>: Anup Jadhav（報告 Claude Code 創造者 Boris Cherny 之洞察）<br><strong>發佈日期</strong>: 2026 年 2 月 15 日<br><strong>來源</strong>: Anup.io</p><hr><h2 id="核心摘要" tabindex="-1">核心摘要 <a class="header-anchor" href="#核心摘要" aria-label="Permalink to &quot;核心摘要&quot;">​</a></h2><p>本文精選了 Boris Cherny（Claude Code 創造者）的 35 項實踐技巧，經過整理成 10 大核心領域。核心理念是將 Claude Code 視為「平行執行引擎，而非聊天機器人」，強調前期規劃、持久知識建設與自動化重複工作流程。</p><h3 id="十大核心領域" tabindex="-1">十大核心領域 <a class="header-anchor" href="#十大核心領域" aria-label="Permalink to &quot;十大核心領域&quot;">​</a></h3><ol><li><strong>並行會話</strong> — 使用 git worktrees 同時運行多個 Claude Code 實例，被視為「單一最大生產力解鎖」</li><li><strong>模型選擇</strong> — 承諾單一模型（Opus 4.5 搭配思考）並在切換前衡量重新提示率</li><li><strong>計畫模式優先</strong> — 複雜任務先在計畫模式迭代至滿意，再轉為自動接受</li><li><strong>活文件</strong> — 維護共享 CLAUDE.md，記錄 Claude 錯誤防止重複</li><li><strong>斜線命令</strong> — 在 .claude/commands/ 中為每日執行多次的工作流程建立命令</li><li><strong>Subagents</strong> — 使用 subagents 處理常見 PR 工作流程與平行 codebase 探索</li><li><strong>自動化 Hooks</strong> — 實作 PostToolUse hooks 進行自動格式化與權限路由</li><li><strong>驗證迴圈</strong> — 最關鍵洞察：啟用 Claude 自我驗證工作，可 2-3 倍提升最終品質</li><li><strong>工具整合</strong> — 連接 Claude 至現有工具鏈（Slack MCP、BigQuery、Sentry 日誌）</li><li><strong>終端設定</strong> — 自定義狀態列、使用語音聽寫、按任務組織標籤</li></ol><hr><h2 id="關鍵實踐詳解" tabindex="-1">關鍵實踐詳解 <a class="header-anchor" href="#關鍵實踐詳解" aria-label="Permalink to &quot;關鍵實踐詳解&quot;">​</a></h2><p><strong>驗證迴圈（最重要）</strong></p><blockquote><p>「給 Claude 一個驗證其工作的方法」是品質改善的關鍵，可 2-3 倍提升最終結果</p></blockquote><p><strong>文件化系統</strong></p><ul><li>將 CLAUDE.md 視為活檔案，記錄錯誤與教訓</li><li>建立累積性知識庫，隨時間改善</li><li>新手開發者從文件開始，重現錯誤從此避免</li></ul><p><strong>模型標準化</strong> 在切換前，承諾單一模型並衡量成效。Opus 4.5 搭配思考模式提供最佳工具使用表現。</p><hr><h2 id="關鍵引用與數據" tabindex="-1">關鍵引用與數據 <a class="header-anchor" href="#關鍵引用與數據" aria-label="Permalink to &quot;關鍵引用與數據&quot;">​</a></h2><blockquote><p>「驗證迴圈將品質提升 2-3 倍」— Boris Cherny</p></blockquote><blockquote><p>「並行執行是單一最大生產力解鎖」</p></blockquote><p><strong>並行規模</strong>: git worktrees 隔離的多個 Claude 實例<br><strong>模型標準</strong>: Opus 4.5 搭配思考模式<br><strong>品質提升</strong>: 驗證迴圈可 2-3 倍改善結果<br><strong>工作流程自動化</strong>: 斜線命令、subagents、hooks 減少重複</p><hr><h2 id="哲學基礎" tabindex="-1">哲學基礎 <a class="header-anchor" href="#哲學基礎" aria-label="Permalink to &quot;哲學基礎&quot;">​</a></h2><p>核心理念是「平行執行引擎」而非聊天機器人，需要前期規劃、知識持久化與工作流程自動化。開發者應認識到 Claude 是強大的工具，但需要明確上下文、持續監督與結構化工作流程。</p>',23)])])}const c=o(s,[["render",i]]);export{g as __pageData,c as default};
